    operand2 = double(operand2);

    % Perform the operation based on the input string
    switch operation
        case '+'
            result = operand1 + operand2;
        case '-'
            result = operand1 - operand2;
        case '*'
            result = operand1 * operand2;
        case '/'
            if operand2 ~= 0
                result = operand1 / operand2;
            else
                error('Division by zero is undefined.');
            end
        otherwise
            error('Unsupported operation. Use one of: +, -, *, /');
    end
end

% Example usage:
% result = simpleCalculator(4, '+', 5);
% disp(result);  % Displays 9
